@pytest.mark.parametrize("schema_name", SCHEMAS, ids=lambda value: value.lower().replace(" ", "_"))
def test_normative_schema_is_registered(schema_name):
    registry = SchemaRegistry.default()

    contract = registry.schema(schema_name)

    assert contract.name == schema_name
    assert contract.normative is True
    assert contract.allows_unknown_fields_only_when_behavior_is_not_weakened is True


@pytest.mark.parametrize("expected", SCHEMA_FIELDS, ids=lambda item: f"{item['schema']}:{item['pointer']}")
def test_normative_schema_declares_json_pointer_field(expected):
    registry = SchemaRegistry.default()

    field = registry.schema(expected["schema"]).field(expected["pointer"])

    assert field.json_pointer == expected["pointer"]
    assert field.defined is True
    assert field.participates_in_validation is True


@pytest.mark.parametrize("expected", SCHEMA_CONTROLS, ids=[item["name"] for item in SCHEMA_CONTROLS])
def test_schema_control_blocks_invalid_artifacts(expected):
    registry = SchemaRegistry.default()

    control = registry.control(expected["name"])

    assert control.statement == expected["statement"]
    assert control.target == expected["target"]
    assert control.enforced is True
    assert control.blocks_invalid_artifacts is expected["blocking"]


def test_added_fields_are_rejected_when_they_weaken_required_behavior():
    policy = ExtensionFieldPolicy()

    decision = policy.evaluate_added_field(
        schema_name="WorkPacket top-level artifact",
        json_pointer="/status_override_that_skips_approval",
        proposed_value="implementation_active",
    )

    assert decision.allowed is False
    assert decision.diagnostic.code == "extension_field_weakens_required_behavior"
